// Get input data (adapt as needed for your JSON structure)
const chars = $('ElevenLabs').first().json.alignment.characters;
const starts = $('ElevenLabs').first().json.alignment.character_start_times_seconds;
const ends = $('ElevenLabs').first().json.alignment.character_end_times_seconds;

// Helper: group characters into words with start/end times
function groupWords(chars, starts, ends) {
  let words = [];
  let word = '';
  let wordStart = null;
  let wordEnd = null;
  for (let i = 0; i < chars.length; i++) {
    if (word === '') wordStart = starts[i];
    word += chars[i];
    wordEnd = ends[i];
    // At space or last char: commit word (excluding spaces)
    if (chars[i] === ' ' || i === chars.length - 1) {
      let cleanText = word.trim();
      if (cleanText.length > 0) {
        words.push({
          start: wordStart,
          end: wordEnd,
          text: cleanText
        });
      }
      word = '';
    }
  }
  return words;
}

// Call the grouping function
const wordObjs = groupWords(chars, starts, ends);

// Convert to n8n output format: array of { json: { ... } }
return wordObjs.map(w => ({ json: w }));

function formatASSTime(t) {
  // ASS expects: H:MM:SS.cs (centiseconds, 2 digits)
  const h = String(Math.floor(t / 3600)).padStart(1, '0');
  const m = String(Math.floor((t % 3600) / 60)).padStart(2, '0');
  const s = String(Math.floor(t % 60)).padStart(2, '0');
  const cs = String(Math.floor((t % 1) * 100)).padStart(2, '0');
  return `${h}:${m}:${s}.${cs}`;
}

// Romanian to Latin-1 replacement (no diacritics)
function toLatin1(str) {
  return str
    .replace(/ă|â|î|ä/g, 'a')
    .replace(/Ă|Â|Î|Ä/g, 'A')
    .replace(/ș|ş/g, 's')
    .replace(/Ș|Ş/g, 'S')
    .replace(/ț|ţ/g, 't')
    .replace(/Ț|Ţ/g, 'T')
    .replace(/é|è|ê|ë/g, 'e')
    .replace(/É|È|Ê|Ë/g, 'E')
    .replace(/ó|ò|ô|õ|ö/g, 'o')
    .replace(/Ó|Ò|Ô|Õ|Ö/g, 'O')
    .replace(/ú|ù|û|ü/g, 'u')
    .replace(/Ú|Ù|Û|Ü/g, 'U')
    .replace(/ç/g, 'c')
    .replace(/Ç/g, 'C')
    .replace(/ă/g, 'a')
    .replace(/Ă/g, 'A')
    .replace(/î/g, 'i')
    .replace(/Î/g, 'I');
}

