const arr = items.map(item => item.json);

// Standard ASS header (Latin-1, no BOM, Arial, 48pt, white on black)
const assHeader = `
[Script Info]
ScriptType: v4.00+
Collisions: Normal
PlayResY: 1080
PlayResX: 1920

[V4+ Styles]
Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding
Style: Default,Arial,48,&H00FFFFFF,&H000000FF,&H00000000,&H64000000,-1,0,0,0,100,100,0,0,1,2,2,2,30,30,50,1

[Events]
Format: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text
`.trim();

// Create dialogue lines, escaping curly braces and converting to Latin-1
const assEvents = arr.map(entry =>
  `Dialogue: 0,${formatASSTime(entry.start)},${formatASSTime(entry.end)},Default,,0,0,0,,${toLatin1(entry.text).replace(/}/g, '\\}').replace(/{/g, '\\{')}`
).join('\n');

// Full ASS content
const ass = assHeader + '\n' + assEvents;

// Generate random filename
const rand = Math.floor(Math.random() * 1e7); // 7 digits
const filename = `subtitles_${rand}.ass`;

// Return as both plain text and n8n file, encoded Latin-1
return [{
  json: {
    ass_text: ass,           // Plain ASS text (Latin-1, no BOM)
    ass_filename: filename   // Random filename for reference
  },
  binary: {
    data: {
      data: Buffer.from(ass, 'latin1'), // Latin-1 buffer, NO BOM!
      mimeType: 'text/plain',
      fileName: filename
    }
  }
}];
